const DEG=Math.PI/180;
function solveKepler(M,e){M=M%(2*Math.PI);if(M>Math.PI)M-=2*Math.PI;if(M<-Math.PI)M+=2*Math.PI;let E=e<0.8?M:Math.PI*Math.sign(M||1);for(let k=0;k<20;k++){const f=E-e*Math.sin(E)-M;const d=f/(1-e*Math.cos(E));E-=d;if(Math.abs(d)<1e-9)break;}return E;}
function pos(el,t){const M=(el.ma+el.n*(t-el.epoch))*DEG;const E=solveKepler(M,el.e);
const xp=el.a*(Math.cos(E)-el.e),yp=el.a*Math.sqrt(1-el.e*el.e)*Math.sin(E);
const w=el.w*DEG,om=el.om*DEG,inc=el.i*DEG;
const cw=Math.cos(w),sw=Math.sin(w),co=Math.cos(om),so=Math.sin(om),ci=Math.cos(inc),si=Math.sin(inc);
const x=xp*(cw*co-sw*so*ci)+yp*(-sw*co-cw*so*ci);
const y=xp*(cw*so+sw*co*ci)+yp*(-sw*so+cw*co*ci);
const z=xp*(sw*si)+yp*(cw*si);
return [x,y,z];}
const planets=require('./data/planets.json');
